-- ============ 工具函数（核心依赖层）============

-- 位运算XOR
local function _bx(a, b)
    local r = 0
    local m = 1
    for _ = 1, 8 do
        if (a % 2) ~= (b % 2) then r = r + m end
        m = m * 2
        a = math.floor(a / 2)
        b = math.floor(b / 2)
    end
    return r
end

-- XOR编解码
local function _xc(s, k)
    local r = {}
    for i = 1, #s do
        r[i] = string.char(_bx(string.byte(s, i), string.byte(k, (i - 1) % #k + 1)))
    end
    return table.concat(r)
end

-- 十六进制解码
local function _fh(s)
    local r = {}
    for i = 1, #s, 2 do
        r[#r + 1] = string.char(tonumber(s:sub(i, i + 1), 16))
    end
    return table.concat(r)
end

-- 十六进制编码
local function _th(s)
    local r = {}
    for i = 1, #s do
        r[#r] = string.format("%02x", string.byte(s, i))
    end
    return table.concat(r)
end

-- ============ 卡密验证核心 ============
local _0k = "xy435116694754"  -- 主密钥
local _0t = nil               -- 运行时令牌（验证后设置）
local _0v = false             -- 验证状态

-- 编码卡密（用于比对）
local function _ek(key)
    local raw = _xc(key, _0k)
    local hex = ""
    for i = 1, #raw do
        hex = hex .. string.format("%02x", string.byte(raw, i))
    end
    return hex
end

-- 验证卡密
local function _vk(input)
    if not input or #input ~= 19 then return false end
    local encoded = _ek(input)
    for i = 1, #_0x do
        if _0x[i] == encoded then
            _0t = input
            _0v = true
            return true
        end
    end
    return false
end

-- ============ 受保护字符串解码（依赖卡密令牌）============
-- 关键：如果 _0t 为 nil，解码结果为乱码，脚本功能失效
-- 删除卡密行 → _0t 永远为 nil → 所有受保护字符串变乱码

local function _ds(hex_str)
    if not _0t then return nil end
    local key = _0t .. _0k
    local raw = _fh(hex_str)
    return _xc(raw, key)
end

-- 预编码的关键字符串（使用第一个卡密作为编码密钥）
-- 这些字符串在运行时通过 _0t 解密
-- 编码方式: XOR(原始字符串, "E4QP-H3RC-J9L4-F5KS" + "xy435116694754")
local _P = {
    search_val   = "741a61",  -- "1.0"
    author       = "3d4d65631879026475147e0e7900",  -- "xy435116694754"
    app_name     = "105a382454adb9f2aaadd5dcd59c",  -- "Unity加速器"
    time_scale   = "115d3c357e2b523e26",  -- "TimeScale"
    unity_tag    = "105a382454adb9f2aaadd5dcd59c0d30006563",  -- "Unity加速器 v5.0"
    about_info   = "105a382454adb9f2aaadd5dcd59c0d3000",  -- "Unity加速器 v5"
}

-- ============ 安全获取受保护字符串 ============
local function _gs(key)
    local v = _ds(_P[key])
    if not v then
        -- 令牌缺失，返回乱码让脚本看似运行但功能失效
        return "ERR_" .. tostring(math.random(1000, 9999))
    end
    return v
end

-- ============ 设备绑定 ============
local function _getDeviceId()
    local pkg = gg.getSelectedPackage() or ""
    local file = gg.getFile() or ""
    return file .. "|" .. pkg
end

local function _getSavePath()
    local dir = gg.getFile():match("(.*[/\\])") or "/sdcard/"
    return dir .. ".unity_key"
end

local function _saveActivation(key)
    local path = _getSavePath()
    local deviceId = _getDeviceId()
    local data = deviceId .. "|" .. key
    local encoded = _ek(data)
    local f = io.open(path, "w")
    if f then
        f:write(encoded)
        f:close()
    end
end

local function _loadActivation()
    local path = _getSavePath()
    local f = io.open(path, "r")
    if not f then return nil end
    local encoded = f:read("*a")
    f:close()
    if not encoded or encoded == "" then return nil end

    local raw = _fh(encoded)
    local decoded = _xc(raw, _0k)
    local deviceId = _getDeviceId()
    local savedDevice = decoded:match("^(.+)|")
    local savedKey = decoded:match("|(.+)$")

    if savedDevice ~= deviceId then return nil end
    return savedKey
end

