-- ============ Unity引擎检测 ============
function detectUnity()
    local pkg = gg.getSelectedPackage()
    if not pkg then return false, "未选中进程" end

    local coreHits = {}
    local auxHits = {}
    local foundIL2CPP = false

    gg.clearResults()
    local ok1 = pcall(function() gg.searchNumber("h 6C 69 62 75 6E 69 74 79 2E 73 6F", gg.TYPE_BYTE) end)
    if ok1 then
        local cnt = gg.getResultsCount()
        if cnt > 0 then coreHits[#coreHits + 1] = "✅ libunity.so (" .. cnt .. "处)" end
    end

    gg.clearResults()
    local ok2 = pcall(function() gg.searchNumber("h 55 6E 69 74 79 45 6E 67 69 6E 65 2E 54 69 6D 65", gg.TYPE_BYTE) end)
    if ok2 then
        local cnt = gg.getResultsCount()
        if cnt > 0 then coreHits[#coreHits + 1] = "✅ UnityEngine.Time (" .. cnt .. "处)" end
    end

    gg.clearResults()
    local ok3 = pcall(function() gg.searchNumber("h 54 69 6D 65 2E 74 69 6D 65 53 63 61 6C 65", gg.TYPE_BYTE) end)
    if ok3 then
        local cnt = gg.getResultsCount()
        if cnt > 0 then auxHits[#auxHits + 1] = "✅ Time.timeScale (" .. cnt .. "处)" end
    end

    gg.clearResults()
    local ok4 = pcall(function() gg.searchNumber("h 54 69 6D 65 2E 66 69 78 65 64 44 65 6C 74 61 54 69 6D 65", gg.TYPE_BYTE) end)
    if ok4 then
        local cnt = gg.getResultsCount()
        if cnt > 0 then auxHits[#auxHits + 1] = "✅ Time.fixedDeltaTime (" .. cnt .. "处)" end
    end

    gg.clearResults()
    local ok5 = pcall(function() gg.searchNumber("h 54 69 6D 65 2E 6D 61 78 69 6D 75 6D 44 65 6C 74 61 54 69 6D 65", gg.TYPE_BYTE) end)
    if ok5 then
        local cnt = gg.getResultsCount()
        if cnt > 0 then auxHits[#auxHits + 1] = "✅ Time.maximumDeltaTime (" .. cnt .. "处)" end
    end

    gg.clearResults()
    local ok6 = pcall(function() gg.searchNumber("h 55 6E 69 74 79 45 6E 67 69 6E 65", gg.TYPE_BYTE) end)
    if ok6 then
        local cnt = gg.getResultsCount()
        if cnt > 0 then auxHits[#auxHits + 1] = "✅ UnityEngine (" .. cnt .. "处)" end
    end

    gg.clearResults()
    local okIl2 = pcall(function() gg.searchNumber("h 6C 69 62 69 6C 32 63 70 70 2E 73 6F", gg.TYPE_BYTE) end)
    if okIl2 and gg.getResultsCount() > 0 then foundIL2CPP = true end
    gg.clearResults()

    local isUnity = (#coreHits >= 1) or (#auxHits >= 2)
    local confidence = #coreHits >= 1 and "🔴 核心特征命中" or (#auxHits >= 2 and "🟡 辅助特征多重命中" or "⚪ 特征不足")

    local report = "━━━ 引擎检测 ━━━\n\n📦 包名: " .. pkg .. "\n🎯 可信度: " .. confidence .. "\n\n🎮 引擎: " .. (isUnity and "✅ Unity" or "❌ 非Unity") .. "\n\n━━━ 核心特征 ━━━\n"
    for i = 1, #coreHits do report = report .. coreHits[i] .. "\n" end
    if #coreHits == 0 then report = report .. "❌ 无命中\n" end
    report = report .. "\n━━━ 辅助特征 ━━━\n"
    for i = 1, #auxHits do report = report .. auxHits[i] .. "\n" end
    if #auxHits == 0 then report = report .. "❌ 无命中\n" end
    if isUnity then
        report = report .. "\n🔧 编译: " .. (foundIL2CPP and "IL2CPP" or "Mono")
    else
        report = report .. "\n\n⚠️ timeScale加速仅适用于Unity"
    end
    return isUnity, report, foundIL2CPP
end

