-- ============ 搜索主流程 ============
function searchAndTest()
    local pkg = gg.getSelectedPackage()
    if not pkg then gg.alert("⚠️ 未选中游戏进程") return end

    if isUnityGame == nil then
        gg.toast("🔍 自动检测...")
        local isUnity = detectUnity()
        isUnityGame = isUnity
        if not isUnity then
            local c = gg.choice({"⚠️  仍然继续", "🔙  返回"}, nil, "⚠️ 非Unity引擎，仍然搜索？")
            if c ~= 1 then return end
        end
    elseif isUnityGame == false then
        local c = gg.choice({"⚠️  仍然继续", "🔙  返回"}, nil, "⚠️ 已知非Unity，仍然搜索？")
        if c ~= 1 then return end
    end

    candidates = {}
    gg.toast("🔍 开始搜索...")
    gg.clearResults()

    -- 关键：搜索值使用受保护字符串，删除卡密 = 搜错值 = 找不到
    gg.searchNumber(_gs("search_val"), gg.TYPE_FLOAT)
    local count = gg.getResultsCount()

    if count == 0 then
        gg.alert("❌ 未找到 float " .. _gs("search_val") .. "\n\n请确认区域全选")
        return
    end

    gg.toast("📊 找到 " .. count .. " 个，开始评分...")
    local keepInput = gg.prompt({"保留得分前N个"}, {"1000"}, {"number"})
    local KEEP = keepInput and tonumber(keepInput[1]) or 1000
    if KEEP < 10 then KEEP = 10 end

    local BATCH = 8000
    local offset = 0
    while offset < count do
        local bc = math.min(BATCH, count - offset)
        local results = gg.getResults(bc, offset)
        local rl = {}
        for i = 1, #results do
            rl[#rl + 1] = {address = results[i].address + 4, flags = gg.TYPE_FLOAT}
            rl[#rl + 1] = {address = results[i].address + 8, flags = gg.TYPE_FLOAT}
        end
        local vals = gg.getValues(rl)
        for i = 1, #results do
            local v2 = vals[(i-1)*2+1].value
            local v3 = vals[(i-1)*2+2].value
            candidates[#candidates+1] = {address=results[i].address, score=calcScore(v2,v3), val2=v2, val3=v3}
        end
        offset = offset + bc
        gg.toast("📊 " .. math.min(offset,count) .. "/" .. count)
    end

    table.sort(candidates, function(a,b) return a.score > b.score end)
    if #candidates > KEEP then
        local t = {}
        for i = 1, KEEP do t[i] = candidates[i] end
        candidates = t
    end

    local info = "━━━ 评分完成 ━━━\n\n搜到 " .. count .. " 个\n候选 " .. #candidates .. " 个\n最高分 " .. (candidates[1] and candidates[1].score or 0)
    gg.alert(info)
    binarySearch()
end

-- ============ 评分 ============
function calcScore(val2, val3)
    local s = 0
    if isGoodFloat(val2) then
        s = s + 50
        if near(val2, 0.333333) then s = s + 40 end
        if near(val2, 0.033333) then s = s + 40 end
        if near(val2, 0.02) then s = s + 35 end
        if near(val2, 0.016666) or near(val2, 0.0167) then s = s + 35 end
        if near(val2, 0.1) then s = s + 30 end
        if near(val2, 0.05) then s = s + 20 end
        if near(val2, 0.03) then s = s + 35 end
        if val2 > 0 and val2 < 0.5 then s = s + 15 end
        if val2 >= 5.0 then s = s - 30 end
    else s = -100 end
    if isGoodFloat(val3) then
        s = s + 20
        if near(val3, 0.1) then s = s + 30 end
        if near(val3, 0.333333) then s = s + 25 end
        if near(val3, 0.05) then s = s + 20 end
        if near(val3, 0.03) then s = s + 25 end
        if near(val3, 0.02) then s = s + 20 end
        if val3 > 0 and val3 < 0.5 then s = s + 10 end
        if val3 >= 5.0 then s = s - 20 end
    else s = s - 30 end
    if isGoodFloat(val2) and isGoodFloat(val3) then
        for _, c in ipairs(CLASSIC_COMBOS) do
            if near(val2, c[1]) and near(val3, c[2]) then s = s + 50; break end
        end
    end
    return s
end

-- ============ 二分法 ============
function binarySearch()
    if #candidates == 0 then gg.alert("❌ 无候选") return end
    local lo, hi = 1, #candidates
    while lo < hi do
        local mid = math.floor((lo + hi) / 2)
        local ml = {}
        for i = lo, mid do ml[#ml+1] = {address=candidates[i].address, flags=gg.TYPE_FLOAT, value=5.0} end
        gg.setValues(ml)
        local c = gg.choice({"✅ 变了", "❌ 没变"}, nil, "⚡ 二分 #"..lo.."~#"..mid.." vs #"..(mid+1).."~#"..hi.."\n已改5.0x，变了吗？")
        local rl = {}
        for i = lo, mid do rl[#rl+1] = {address=candidates[i].address, flags=gg.TYPE_FLOAT, value=1.0} end
        gg.setValues(rl)
        if c == 1 then hi = mid elseif c == 2 then lo = mid + 1 else return end
        if hi - lo < 5 then testOneByOne(lo, hi) return end
    end
    testSingle(lo)
end

function testOneByOne(lo, hi)
    for i = lo, hi do
        gg.setValues({{address=candidates[i].address, flags=gg.TYPE_FLOAT, value=5.0}})
        local c = gg.choice({"✅ 是它！", "❌ 下一个", "🔙 退出"}, nil,
            "🎯 "..(i-lo+1).."/"..(hi-lo+1).." ⭐"..candidates[i].score.." "..string.format("0x%X",candidates[i].address).."\n5.0x 变了吗？")
        if c == 1 then speedAddr = candidates[i].address; currentSpeed = 5.0; onSaveFound(); return
        elseif c == 3 then gg.setValues({{address=candidates[i].address, flags=gg.TYPE_FLOAT, value=1.0}}); return end
        gg.setValues({{address=candidates[i].address, flags=gg.TYPE_FLOAT, value=1.0}})
    end
    gg.alert("❌ 未找到")
end

function testSingle(idx)
    gg.setValues({{address=candidates[idx].address, flags=gg.TYPE_FLOAT, value=5.0}})
    local c = gg.choice({"✅ 是它！", "❌ 不是"}, nil, "🎯 最后1个 "..string.format("0x%X",candidates[idx].address))
    if c == 1 then speedAddr = candidates[idx].address; currentSpeed = 5.0; onSaveFound()
    else gg.setValues({{address=candidates[idx].address, flags=gg.TYPE_FLOAT, value=1.0}}); gg.alert("❌ 未找到") end
end

-- ============ 保存到GG列表 ============
function onSaveFound()
    removeOldSaves()
    local pkg = gg.getSelectedPackage() or "unknown"
    local note = SAVE_TAG .. " | " .. pkg .. " | " .. string.format("0x%X", speedAddr) .. " | " .. currentSpeed .. "x | " .. _gs("author")
    gg.addListItems({{address=speedAddr, flags=gg.TYPE_FLOAT, name=note, value=currentSpeed}})
    gg.alert("✅ 锁定！\n📍 "..string.format("0x%X",speedAddr).."\n🚀 "..currentSpeed.."x\n💾 已保存")
end

function removeOldSaves()
    local items = gg.getListItems()
    local rm = {}
    for i = 1, #items do if items[i].name and string.find(items[i].name, "TimeScale") then rm[#rm+1] = i end end
    if #rm > 0 then gg.removeListItems(rm) end
end

function loadFromSaveList()
    local items = gg.getListItems()
    for i = 1, #items do if items[i].name and string.find(items[i].name, "TimeScale") then return items[i] end end
    return nil
end

function loadFromSaveListMenu()
    local saved = loadFromSaveList()
    if not saved then gg.alert("❌ 列表中无记录") return end
    speedAddr = saved.address; currentSpeed = saved.value
    local c = gg.choice({"⚡ 加载", "🔄 恢复1.0x", "🗑️ 移除", "🔙 返回"}, nil, "💾 "..string.format("0x%X",speedAddr).." "..currentSpeed.."x")
    if c == 1 then gg.toast("✅ 已加载")
    elseif c == 2 then applySpeed(1.0)
    elseif c == 3 then removeOldSaves(); speedAddr = nil; currentSpeed = 1.0; gg.toast("🗑️ 已移除") end
end

function showSaveListInfo()
    local saved = loadFromSaveList()
    if not saved then gg.alert("📋 无记录") return end
    local c = gg.choice({"🚀 改倍率", "🔄 恢复1.0x", "🗑️ 移除", "🔙 返回"}, nil, "💾 "..string.format("0x%X",saved.address).." "..saved.value.."x")
    if c == 1 then setSpeedDialog() elseif c == 2 then resetSpeed() elseif c == 3 then removeOldSaves(); speedAddr = nil; currentSpeed = 1.0 end
end

-- ============ 工具 ============
function isGoodFloat(v)
    if v == nil or v ~= v or v == math.huge or v == -math.huge or v < -10000 or v > 10000 then return false end
    return true
end
function near(v, t) return math.abs(v - t) < 0.001 end

-- ============ 速度控制 ============
function setSpeedDialog()
    local input = gg.prompt({"🚀 倍率"}, {tostring(currentSpeed)}, {"number"})
    if not input then return end
    local s = tonumber(input[1])
    if not s or s < 0.001 or s > 1000 then gg.alert("⚠️ 0.001~1000") return end
    applySpeed(s)
end

function quickSpeedUp()
    local c = gg.choice({"🔥 2x","🔥 3x","🔥 5x","🔥 10x","🔥 20x","✏️ 自定义"}, nil, "⏩ 加速 ["..currentSpeed.."x]")
    if not c then return end
    local sp = {2,3,5,10,20}
    if c <= 5 then applySpeed(sp[c]) else setSpeedDialog() end
end

function quickSlowDown()
    local c = gg.choice({"🐌 0.5x","🐌 0.25x","🐌 0.1x","🐌 0.01x","✏️ 自定义"}, nil, "⏪ 减速 ["..currentSpeed.."x]")
    if not c then return end
    local sp = {0.5,0.25,0.1,0.01}
    if c <= 4 then applySpeed(sp[c]) else setSpeedDialog() end
end

function applySpeed(s)
    if not speedAddr then gg.alert("⚠️ 请先搜索") return end
    gg.setValues({{address=speedAddr, flags=gg.TYPE_FLOAT, value=s}})
    currentSpeed = s; updateSaveListItem(s); gg.toast("🚀 "..s.."x")
end

function updateSaveListItem(s)
    removeOldSaves()
    local pkg = gg.getSelectedPackage() or "unknown"
    local note = SAVE_TAG.." | "..pkg.." | "..string.format("0x%X",speedAddr).." | "..s.."x | ".._gs("author")
    gg.addListItems({{address=speedAddr, flags=gg.TYPE_FLOAT, name=note, value=s}})
end

function resetSpeed()
    if not speedAddr then return end
    gg.setValues({{address=speedAddr, flags=gg.TYPE_FLOAT, value=1.0}})
    currentSpeed = 1.0; updateSaveListItem(1.0); gg.toast("🔄 1.0x")
end

